---@meta

-- Grid Protocol — Element Type Annotations
-- LuaCATS annotations for Grid firmware element-method API
-- https://github.com/intechstudio/grid-protocol
--
-- Each element type (Button, Potmeter, Encoder, Endless, LCD, System) is
-- modelled as a @class.  In user code these are accessed as `self:method()`
-- inside event callbacks, or `element[i]:method()` from any context.
--
-- Hand-enriched entries give full @param / @return detail.
-- Entries generated by scaffold_annotations.py are marked [scaffold].

---------------------------------------------------------------------------
-- Shared fields
---------------------------------------------------------------------------

---@class ElementBase
---@field type string Element type identifier
local ElementBase = {}

---Returns the zero-based element index.
---@return integer index
function ElementBase:element_index() end

---Returns the hardware LED index for this element.
---@return integer led_index
function ElementBase:led_index() end

---Gets or sets the element display name.
---@param name? string Optional name to set
---@return string name
function ElementBase:element_name(name) end

---------------------------------------------------------------------------
-- ButtonElement
---------------------------------------------------------------------------

---@class ButtonElement : ElementBase
local ButtonElement = {}

---Gets or sets the button value.
---@param value? integer Value to set (0–127 by default)
---@return integer value Current button value
function ButtonElement:button_value(value) end

---Gets or sets the button minimum.
---@param value? integer Minimum to set
---@return integer min Current minimum
function ButtonElement:button_min(value) end

---Gets or sets the button maximum.
---@param value? integer Maximum to set
---@return integer max Current maximum
function ButtonElement:button_max(value) end

---Gets or sets the button mode (step count). 0 = momentary.
---@param value? integer Mode / step count
---@return integer mode Current mode
function ButtonElement:button_mode(value) end

---Returns the elapsed time since last button event in ms.
---@return integer ms
function ButtonElement:button_elapsed_time() end

---Returns the button state (0 = released, 127 = pressed).
---@return integer state
function ButtonElement:button_state() end

---Returns the current step index, or false if mode is 0.
---@return integer|false step
function ButtonElement:button_step() end

---Sets or gets the LED color for this element.
---@param layer integer LED layer index
---@param colors table Color specification
function ButtonElement:led_color(layer, colors) end

