---------------------------------------------------------------------------
-- LcdElement
---------------------------------------------------------------------------

---@class LcdElement : ElementBase
local LcdElement = {}

---Returns the screen index used by low-level draw APIs.
---@return integer screen_index
function LcdElement:screen_index() end

---Returns the screen width in pixels.
---@return integer width
function LcdElement:screen_width() end

---Returns the screen height in pixels.
---@return integer height
function LcdElement:screen_height() end

---Swaps the background buffer to the screen.
function LcdElement:draw_swap() end

---Draws a pixel at (x, y).
---@param x integer
---@param y integer
---@param color integer[] {r, g, b}
function LcdElement:draw_pixel(x, y, color) end

---Draws a line.
---@param x1 integer
---@param y1 integer
---@param x2 integer
---@param y2 integer
---@param color integer[] {r, g, b}
function LcdElement:draw_line(x1, y1, x2, y2, color) end

---Draws a rectangle outline.
---@param x1 integer
---@param y1 integer
---@param x2 integer
---@param y2 integer
---@param color integer[] {r, g, b}
function LcdElement:draw_rectangle(x1, y1, x2, y2, color) end

---Draws a filled rectangle.
---@param x1 integer
---@param y1 integer
---@param x2 integer
---@param y2 integer
---@param color integer[] {r, g, b}
function LcdElement:draw_rectangle_filled(x1, y1, x2, y2, color) end

---Draws a rounded rectangle outline.
---@param x1 integer
---@param y1 integer
---@param x2 integer
---@param y2 integer
---@param radius integer Corner radius in pixels
---@param color integer[] {r, g, b}
function LcdElement:draw_rectangle_rounded(x1, y1, x2, y2, radius, color) end

---Draws a filled rounded rectangle.
---@param x1 integer
---@param y1 integer
---@param x2 integer
---@param y2 integer
---@param radius integer Corner radius in pixels
---@param color integer[] {r, g, b}
function LcdElement:draw_rectangle_rounded_filled(x1, y1, x2, y2, radius, color) end

---Draws a polygon outline.
---@param xs integer[] X coordinates
---@param ys integer[] Y coordinates
---@param color integer[] {r, g, b}
function LcdElement:draw_polygon(xs, ys, color) end

---Draws a filled polygon.
---@param xs integer[] X coordinates
---@param ys integer[] Y coordinates
---@param color integer[] {r, g, b}
function LcdElement:draw_polygon_filled(xs, ys, color) end

---Draws text.
---@param text string
---@param x integer
---@param y integer
---@param size integer Font size
---@param color integer[] {r, g, b}
function LcdElement:draw_text(text, x, y, size, color) end

---Draws text using the fast renderer.
---@param text string
---@param x integer
---@param y integer
---@param size integer Font size
---@param color integer[] {r, g, b}
function LcdElement:draw_text_fast(text, x, y, size, color) end

---Fills an area without alpha blending.
---@param x1 integer
---@param y1 integer
---@param x2 integer
---@param y2 integer
---@param color integer[] {r, g, b}
function LcdElement:draw_area_filled(x1, y1, x2, y2, color) end

---Draws the n-th demo iteration.
---@param n integer
function LcdElement:draw_demo(n) end

---Returns render time between last two swaps, in µs.
---@return integer us
function LcdElement:get_render_time() end

---------------------------------------------------------------------------
-- SystemElement
---------------------------------------------------------------------------

---@class SystemElement : ElementBase
local SystemElement = {}

---------------------------------------------------------------------------
-- Element array
---------------------------------------------------------------------------

---The global element array; element[0] is typically the system element,
---element[1..N] are the physical controls.
---@type (ButtonElement|PotmeterElement|EncoderElement|EndlessElement|LcdElement|SystemElement)[]
element = {}

---Reference to the current element inside an event callback.
---@type ButtonElement|PotmeterElement|EncoderElement|EndlessElement|LcdElement|SystemElement
self = nil
